from flask import Flask, request, render_template, redirect, url_for, session, flash
import secrets
import hashlib
import time
from datetime import datetime, timedelta

app = Flask(__name__)
app.secret_key = secrets.token_hex(16)

# Mock user database
users = {
    "admin": {
        "password": hashlib.sha256("password123".encode()).hexdigest(),
        "mfa_secret": "GHSXG4TBOI6TQ2ZP"
    }
}

# Mock MFA tokens
mfa_tokens = {}

@app.route('/')
def index():
    if 'user_id' in session:
        return redirect(url_for('dashboard'))
    return redirect(url_for('login'))

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']
        
        if username in users:
            hashed_password = hashlib.sha256(password.encode()).hexdigest()
            if hashed_password == users[username]["password"]:
                session['user_id'] = username
                session['mfa_verified'] = False
                return redirect(url_for('verify_mfa'))
        
        flash('Invalid username or password')
        return render_template('login.html')
    
    return render_template('login.html')

@app.route('/verify-mfa', methods=['GET', 'POST'])
def verify_mfa():
    if 'user_id' not in session:
        return redirect(url_for('login'))
    
    if session.get('mfa_verified', False):
        return redirect(url_for('dashboard'))
    
    if request.method == 'POST':
        token = request.form['token']
        user_id = session['user_id']
        
        # Generate expected token
        import pyotp
        totp = pyotp.TOTP(users[user_id]["mfa_secret"])
        expected_token = totp.now()
        
        if token == expected_token:
            session['mfa_verified'] = True
            return redirect(url_for('dashboard'))
        else:
            flash('Invalid MFA token')
            return render_template('verify_mfa.html')
    
    return render_template('verify_mfa.html')

@app.route('/dashboard')
def dashboard():
    if 'user_id' not in session or not session.get('mfa_verified', False):
        return redirect(url_for('login'))
    
    return f"Welcome {session['user_id']}! This is a protected resource."

if __name__ == '__main__':
    app.run(debug=True)